     1→'use client';
     2→
     3→/**
     4→ * LiveMindmap Component
     5→ *
     6→ * Combines InteractiveMarkMapRenderer with SSE event listening for real-time
     7→ * voice command modifications. This is the primary mindmap component for
     8→ * conversation-first tool building.
     9→ *
    10→ * Part of Phase 7: Voice Commands for Mindmaps
    11→ */
    12→
    13→import { useRef, useCallback } from 'react';
    14→import {
    15→  InteractiveMarkMapRenderer,
    16→  type InteractiveMarkMapHandle,
    17→  type InteractiveMarkMapRendererProps,
    18→} from './interactive-markmap-renderer';
    19→import {
    20→  useMindmapModifications,
    21→  type MindmapModificationCallbacks,
    22→} from '@/lib/hooks/use-mindmap-modifications';
    23→import { logger } from '@/lib/logger';
    24→import type { MindmapNode } from './markmap-renderer';
    25→
    26→// ============================================================================
    27→// TYPES
    28→// ============================================================================
    29→
    30→export interface LiveMindmapProps extends Omit<InteractiveMarkMapRendererProps, 'ref'> {
    31→  /** Session ID for SSE subscription */
    32→  sessionId: string | null;
    33→  /** Whether to listen for SSE events (default: true when sessionId provided) */
    34→  listenForEvents?: boolean;
    35→  /** Callback when nodes change (for persisting) */
    36→  onNodesChange?: (nodes: MindmapNode[]) => void;
    37→  /** Callback when a modification is received */
    38→  onModification?: (command: string, args: Record<string, unknown>) => void;
    39→}
    40→
    41→// ============================================================================
    42→// COMPONENT
    43→// ============================================================================
    44→
    45→export function LiveMindmap({
    46→  sessionId,
    47→  listenForEvents = true,
    48→  onNodesChange,
    49→  onModification,
    50→  ...rendererProps
    51→}: LiveMindmapProps) {
    52→  const rendererRef = useRef<InteractiveMarkMapHandle>(null);
    53→
    54→  // Define modification callbacks
    55→  const callbacks: MindmapModificationCallbacks = {
    56→    onAddNode: useCallback(
    57→      (concept: string, parentNode?: string) => {
    58→        if (rendererRef.current) {
    59→          rendererRef.current.addNode(concept, parentNode);
    60→          onModification?.('mindmap_add_node', { concept, parentNode });
    61→        }
    62→      },
    63→      [onModification]
    64→    ),
    65→
    66→    onConnectNodes: useCallback(
    67→      (nodeA: string, nodeB: string) => {
    68→        if (rendererRef.current) {
    69→          rendererRef.current.connectNodes(nodeA, nodeB);
    70→          onModification?.('mindmap_connect_nodes', { nodeA, nodeB });
    71→        }
    72→      },
    73→      [onModification]
    74→    ),
    75→
    76→    onExpandNode: useCallback(
    77→      (node: string, suggestions?: string[]) => {
    78→        if (rendererRef.current) {
    79→          rendererRef.current.expandNode(node, suggestions);
    80→          onModification?.('mindmap_expand_node', { node, suggestions });
    81→        }
    82→      },
    83→      [onModification]
    84→    ),
    85→
    86→    onDeleteNode: useCallback(
    87→      (node: string) => {
    88→        if (rendererRef.current) {
    89→          rendererRef.current.deleteNode(node);
    90→          onModification?.('mindmap_delete_node', { node });
    91→        }
    92→      },
    93→      [onModification]
    94→    ),
    95→
    96→    onFocusNode: useCallback(
    97→      (node: string) => {
    98→        if (rendererRef.current) {
    99→          rendererRef.current.focusNode(node);
   100→          onModification?.('mindmap_focus_node', { node });
   101→        }
   102→      },
   103→      [onModification]
   104→    ),
   105→
   106→    onSetColor: useCallback(
   107→      (node: string, color: string) => {
   108→        if (rendererRef.current) {
   109→          rendererRef.current.setNodeColor(node, color);
   110→          onModification?.('mindmap_set_color', { node, color });
   111→        }
   112→      },
   113→      [onModification]
   114→    ),
   115→  };
   116→
   117→  // Subscribe to SSE modifications
   118→  const { isConnected } = useMindmapModifications({
   119→    sessionId,
   120→    enabled: listenForEvents && !!sessionId,
   121→    callbacks,
   122→  });
   123→
   124→  // Handle nodes change from renderer
   125→  const handleNodesChange = useCallback(
   126→    (nodes: MindmapNode[]) => {
   127→      onNodesChange?.(nodes);
   128→    },
   129→    [onNodesChange]
   130→  );
   131→
   132→  logger.debug('[LiveMindmap] Render', {
   133→    sessionId,
   134→    listenForEvents,
   135→    isConnected,
   136→  });
   137→
   138→  return (
   139→    <InteractiveMarkMapRenderer
   140→      ref={rendererRef}
   141→      {...rendererProps}
   142→      onNodesChange={handleNodesChange}
   143→    />
   144→  );
   145→}
   146→
   147→// Re-export types for convenience
   148→export type { MindmapNode, InteractiveMarkMapHandle };
