   197→// ============================================================================
   198→// COMPONENT
   199→// ============================================================================
   200→
   201→export const InteractiveMarkMapRenderer = forwardRef<
   202→  InteractiveMarkMapHandle,
   203→  InteractiveMarkMapRendererProps
   204→>(function InteractiveMarkMapRenderer(
   205→  { title, initialMarkdown, initialNodes, className, onNodesChange },
   206→  ref
   207→) {
   208→  const svgRef = useRef<SVGSVGElement>(null);
   209→  const containerRef = useRef<HTMLDivElement>(null);
   210→  const markmapRef = useRef<Markmap | null>(null);
   211→
   212→  const [error, setError] = useState<string | null>(null);
   213→  const [rendered, setRendered] = useState(false);
   214→  const [zoom, setZoom] = useState(1);
   215→  const [accessibilityMode, setAccessibilityMode] = useState(false);
   216→  const [isFullscreen, setIsFullscreen] = useState(false);
   217→
   218→  // Internal node state for modifications
   219→  const [nodes, setNodesState] = useState<MindmapNode[]>(() => {
   220→    if (initialNodes && initialNodes.length > 0) {
   221→      return cloneNodes(initialNodes);
   222→    }
   223→    if (initialMarkdown) {
   224→      return markdownToNodes(initialMarkdown);
   225→    }
   226→    return [];
   227→  });
   228→
   229→  // Undo history
   230→  const [history, setHistory] = useState<MindmapNode[][]>([]);
   231→
   232→  const { settings } = useAccessibilityStore();
   233→
   234→  // Save state for undo
   235→  const saveToHistory = useCallback(() => {
   236→    setHistory((prev) => [...prev.slice(-20), cloneNodes(nodes)]);
   237→  }, [nodes]);
   238→
   239→  // Update nodes and notify parent
   240→  const updateNodes = useCallback(
   241→    (newNodes: MindmapNode[]) => {
   242→      saveToHistory();
   243→      setNodesState(newNodes);
   244→      onNodesChange?.(newNodes);
   245→    },
   246→    [saveToHistory, onNodesChange]
   247→  );
   248→
   249→  // ============================================================================
   250→  // MODIFICATION METHODS
   251→  // ============================================================================
   252→
   253→  const addNode = useCallback(
   254→    (concept: string, parentNodeLabel?: string): boolean => {
   255→      const newNode: MindmapNode = {
   256→        id: nanoid(8),
   257→        label: concept,
   258→        children: [],
   259→      };
   260→
   261→      if (!parentNodeLabel) {
   262→        // Add to root level
   263→        updateNodes([...nodes, newNode]);
   264→        logger.info('[InteractiveMarkmap] Added root node', { concept });
   265→        return true;
   266→      }
   267→
   268→      // Find parent node
   269→      const found = findNodeByLabel(nodes, parentNodeLabel);
   270→      if (!found) {
   271→        // If parent not found, add to root
   272→        updateNodes([...nodes, newNode]);
   273→        logger.warn('[InteractiveMarkmap] Parent not found, added to root', {
   274→          concept,
   275→          parentNodeLabel,
   276→        });
   277→        return true;
   278→      }
   279→
   280→      // Add to parent
   281→      const newNodes = cloneNodes(nodes);
   282→      const parentInClone = findNodeByLabel(newNodes, parentNodeLabel);
   283→      if (parentInClone) {
   284→        if (!parentInClone.node.children) parentInClone.node.children = [];
   285→        parentInClone.node.children.push(newNode);
   286→        updateNodes(newNodes);
   287→        logger.info('[InteractiveMarkmap] Added child node', {
   288→          concept,
   289→          parentNodeLabel,
   290→        });
   291→        return true;
   292→      }
   293→
   294→      return false;
   295→    },
   296→    [nodes, updateNodes]
   297→  );
   298→
   299→  const expandNode = useCallback(
   300→    (nodeLabel: string, suggestions?: string[]): boolean => {
   301→      const found = findNodeByLabel(nodes, nodeLabel);
   302→      if (!found) {
   303→        logger.warn('[InteractiveMarkmap] Node not found for expand', {
   304→          nodeLabel,
   305→        });
   306→        return false;
   307→      }
   308→
   309→      const newNodes = cloneNodes(nodes);
   310→      const nodeInClone = findNodeByLabel(newNodes, nodeLabel);
   311→      if (!nodeInClone) return false;
   312→
   313→      // Add suggestions as children
   314→      const childLabels = suggestions || [
   315→        `${nodeLabel} - Dettaglio 1`,
   316→        `${nodeLabel} - Dettaglio 2`,
   317→        `${nodeLabel} - Dettaglio 3`,
   318→      ];
   319→
   320→      if (!nodeInClone.node.children) nodeInClone.node.children = [];
   321→      for (const label of childLabels) {
   322→        nodeInClone.node.children.push({
   323→          id: nanoid(8),
   324→          label,
   325→          children: [],
   326→        });
   327→      }
   328→
   329→      updateNodes(newNodes);
   330→      logger.info('[InteractiveMarkmap] Expanded node', {
   331→        nodeLabel,
   332→        childCount: childLabels.length,
   333→      });
   334→      return true;
   335→    },
   336→    [nodes, updateNodes]
   337→  );
   338→
   339→  const deleteNode = useCallback(
   340→    (nodeLabel: string): boolean => {
   341→      const found = findNodeByLabel(nodes, nodeLabel);
   342→      if (!found) {
   343→        logger.warn('[InteractiveMarkmap] Node not found for delete', {
   344→          nodeLabel,
   345→        });
   346→        return false;
   347→      }
   348→
   349→      const newNodes = cloneNodes(nodes);
   350→
   351→      if (!found.parent) {
   352→        // Root level node
   353→        newNodes.splice(found.index, 1);
   354→      } else {
   355→        const parentInClone = findNodeByLabel(newNodes, found.parent.label);
   356→        if (parentInClone && parentInClone.node.children) {
   357→          const idx = parentInClone.node.children.findIndex(
   358→            (c) => c.label.toLowerCase() === found.node.label.toLowerCase()
   359→          );
   360→          if (idx >= 0) {
   361→            parentInClone.node.children.splice(idx, 1);
   362→          }
   363→        }
   364→      }
   365→
   366→      updateNodes(newNodes);
   367→      logger.info('[InteractiveMarkmap] Deleted node', { nodeLabel });
   368→      return true;
   369→    },
   370→    [nodes, updateNodes]
   371→  );
   372→
   373→  const focusNode = useCallback(
   374→    (nodeLabel: string): boolean => {
   375→      if (!markmapRef.current || !svgRef.current) return false;
   376→
   377→      // Find the node in the SVG
   378→      const textElements = svgRef.current.querySelectorAll('text, foreignObject');
   379→      const normalizedLabel = nodeLabel.toLowerCase().trim();
   380→
   381→      for (const el of textElements) {
   382→        const text = el.textContent?.toLowerCase().trim();
   383→        if (text && text.includes(normalizedLabel)) {
   384→          // Get the g element that contains this node
   385→          let parent = el.parentElement;
   386→          while (parent && parent.tagName !== 'g') {
   387→            parent = parent.parentElement;
   388→          }
   389→
   390→          if (parent) {
   391→            // Scroll into view
   392→            parent.scrollIntoView({ behavior: 'smooth', block: 'center' });
   393→
   394→            // Flash highlight
   395→            const svgParent = parent as unknown as SVGElement;
   396→            const originalFill = svgParent.style.fill;
   397→            svgParent.style.fill = '#facc15';
   398→            setTimeout(() => {
   399→              svgParent.style.fill = originalFill;
   400→            }, 1000);
   401→
   402→            logger.info('[InteractiveMarkmap] Focused on node', { nodeLabel });
   403→            return true;
   404→          }
   405→        }
   406→      }
   407→
   408→      logger.warn('[InteractiveMarkmap] Node not found for focus', { nodeLabel });
   409→      return false;
   410→    },
   411→    []
   412→  );
   413→
   414→  const setNodeColor = useCallback(
   415→    (nodeLabel: string, color: string): boolean => {
   416→      const found = findNodeByLabel(nodes, nodeLabel);
   417→      if (!found) {
   418→        logger.warn('[InteractiveMarkmap] Node not found for color', {
   419→          nodeLabel,
   420→        });
   421→        return false;
   422→      }
   423→
   424→      // Resolve color name to hex
   425→      const resolvedColor = COLOR_MAP[color.toLowerCase()] || color;
   426→
   427→      const newNodes = cloneNodes(nodes);
   428→      const nodeInClone = findNodeByLabel(newNodes, nodeLabel);
   429→      if (nodeInClone) {
   430→        nodeInClone.node.color = resolvedColor;
   431→        updateNodes(newNodes);
   432→        logger.info('[InteractiveMarkmap] Set node color', {
   433→          nodeLabel,
   434→          color: resolvedColor,
   435→        });
   436→        return true;
   437→      }
   438→
   439→      return false;
   440→    },
   441→    [nodes, updateNodes]
   442→  );
   443→
   444→  const connectNodes = useCallback(
   445→    (nodeALabel: string, nodeBLabel: string): boolean => {
   446→      // In a tree structure, "connect" means move nodeB under nodeA
   447→      const foundA = findNodeByLabel(nodes, nodeALabel);
   448→      const foundB = findNodeByLabel(nodes, nodeBLabel);
   449→
   450→      if (!foundA || !foundB) {
   451→        logger.warn('[InteractiveMarkmap] Nodes not found for connect', {
   452→          nodeALabel,
   453→          nodeBLabel,
   454→        });
   455→        return false;
   456→      }
   457→
   458→      // Remove nodeB from its current position
   459→      const newNodes = cloneNodes(nodes);
   460→
   461→      // First, find and remove nodeB
   462→      const foundBInClone = findNodeByLabel(newNodes, nodeBLabel);
   463→      if (!foundBInClone) return false;
   464→
   465→      const nodeBCopy = cloneNodes([foundBInClone.node])[0];
   466→
   467→      if (!foundBInClone.parent) {
   468→        // Remove from root
   469→        const idx = newNodes.findIndex(
   470→          (n) => n.label.toLowerCase() === nodeBLabel.toLowerCase()
   471→        );
   472→        if (idx >= 0) newNodes.splice(idx, 1);
   473→      } else {
   474→        const parent = findNodeByLabel(newNodes, foundBInClone.parent.label);
   475→        if (parent && parent.node.children) {
   476→          const idx = parent.node.children.findIndex(
   477→            (c) => c.label.toLowerCase() === nodeBLabel.toLowerCase()
   478→          );
   479→          if (idx >= 0) parent.node.children.splice(idx, 1);
   480→        }
   481→      }
   482→
   483→      // Now add nodeB under nodeA
   484→      const foundAInClone = findNodeByLabel(newNodes, nodeALabel);
   485→      if (foundAInClone) {
   486→        if (!foundAInClone.node.children) foundAInClone.node.children = [];
   487→        foundAInClone.node.children.push(nodeBCopy);
   488→        updateNodes(newNodes);
   489→        logger.info('[InteractiveMarkmap] Connected nodes', {
   490→          nodeALabel,
   491→          nodeBLabel,
   492→        });
   493→        return true;
   494→      }
   495→
   496→      return false;
   497→    },
   498→    [nodes, updateNodes]
   499→  );
   500→
   501→  const undo = useCallback((): boolean => {
   502→    if (history.length === 0) return false;
   503→    const prevState = history[history.length - 1];
   504→    setHistory((h) => h.slice(0, -1));
   505→    setNodesState(prevState);
   506→    onNodesChange?.(prevState);
   507→    logger.info('[InteractiveMarkmap] Undo performed');
   508→    return true;
   509→  }, [history, onNodesChange]);
   510→
   511→  // ============================================================================
   512→  // VIEW METHODS
   513→  // ============================================================================
   514→
   515→  const handleZoomIn = useCallback(() => {
   516→    if (markmapRef.current) {
   517→      markmapRef.current.rescale(1.25);
   518→    }
   519→    setZoom((z) => Math.min(z * 1.25, 3));
   520→  }, []);
   521→
   522→  const handleZoomOut = useCallback(() => {
   523→    if (markmapRef.current) {
   524→      markmapRef.current.rescale(0.8);
   525→    }
   526→    setZoom((z) => Math.max(z * 0.8, 0.5));
   527→  }, []);
   528→
   529→  const handleReset = useCallback(() => {
   530→    if (markmapRef.current) {
   531→      markmapRef.current.fit();
   532→    }
   533→    setZoom(1);
   534→  }, []);
   535→
   536→  const handleFullscreen = useCallback(async () => {
   537→    if (!containerRef.current) return;
   538→
   539→    try {
   540→      if (!document.fullscreenElement) {
   541→        await containerRef.current.requestFullscreen();
   542→        setIsFullscreen(true);
   543→      } else {
   544→        await document.exitFullscreen();
   545→        setIsFullscreen(false);
   546→      }
   547→    } catch (err) {
   548→      logger.error('Fullscreen error', { error: String(err) });
   549→    }
   550→  }, []);
   551→
   552→  // ============================================================================
   553→  // IMPERATIVE HANDLE
   554→  // ============================================================================
   555→
   556→  useImperativeHandle(
   557→    ref,
   558→    () => ({
   559→      addNode,
   560→      expandNode,
   561→      deleteNode,
   562→      focusNode,
   563→      setNodeColor,
   564→      connectNodes,
   565→      zoomIn: handleZoomIn,
   566→      zoomOut: handleZoomOut,
   567→      resetView: handleReset,
   568→      toggleFullscreen: handleFullscreen,
   569→      getNodes: () => cloneNodes(nodes),
   570→      setNodes: (newNodes: MindmapNode[]) => {
   571→        saveToHistory();
   572→        setNodesState(cloneNodes(newNodes));
   573→        onNodesChange?.(newNodes);
   574→      },
   575→      undo,
   576→    }),
   577→    [
   578→      addNode,
   579→      expandNode,
   580→      deleteNode,
   581→      focusNode,
   582→      setNodeColor,
   583→      connectNodes,
   584→      handleZoomIn,
   585→      handleZoomOut,
   586→      handleReset,
   587→      handleFullscreen,
   588→      nodes,
   589→      saveToHistory,
   590→      onNodesChange,
   591→      undo,
   592→    ]
   593→  );
   594→
   595→  // ============================================================================
   596→  // RENDER MINDMAP
   597→  // ============================================================================
   598→
   599→  useEffect(() => {
   600→    const renderMindmap = async () => {
   601→      if (!svgRef.current) return;
   602→
   603→      try {
   604→        setError(null);
   605→        setRendered(false);
   606→
   607→        // Clear previous content
   608→        svgRef.current.innerHTML = '';
   609→
   610→        // Get markdown from nodes
   611→        const content = nodesToMarkdown(nodes, title);
   612→        const { root } = transformer.transform(content);
   613→
   614→        // Determine font family based on accessibility settings
   615→        const fontFamily =
   616→          settings.dyslexiaFont || accessibilityMode
   617→            ? 'OpenDyslexic, Comic Sans MS, sans-serif'
   618→            : 'Arial, Helvetica, sans-serif';
   619→
   620→        // Determine colors based on accessibility settings
   621→        const isHighContrast = settings.highContrast || accessibilityMode;
   622→
   623→        // Create or update markmap
   624→        if (markmapRef.current) {
   625→          markmapRef.current.destroy();
   626→        }
   627→
   628→        markmapRef.current = Markmap.create(
   629→          svgRef.current,
   630→          {
   631→            autoFit: true,
   632→            duration: 300,
   633→            maxWidth: 280,
   634→            paddingX: 16,
   635→            spacingVertical: 8,
   636→            spacingHorizontal: 100,
   637→            initialExpandLevel: 3, // Start with first 3 levels expanded, rest collapsed
   638→            zoom: true, // Enable zoom/pan
   639→            pan: true,  // Enable panning
   640→            color: (node) => {
   641→              if (isHighContrast) {
   642→                const colors = ['#ffff00', '#00ffff', '#ff00ff', '#00ff00', '#ff8000'];
   643→                return colors[node.state?.depth % colors.length] || '#ffffff';
   644→              }
   645→              const colors = ['#3b82f6', '#10b981', '#f59e0b', '#ef4444', '#8b5cf6', '#ec4899'];
   646→              return colors[node.state?.depth % colors.length] || '#64748b';
   647→            },
   648→          },
   649→          root
   650→        );
   651→
   652→        // Apply custom styles after render
   653→        setTimeout(() => {
   654→          if (svgRef.current) {
   655→            const textElements = svgRef.current.querySelectorAll('text, foreignObject');
   656→            textElements.forEach((el) => {
   657→              if (el instanceof SVGElement || el instanceof HTMLElement) {
   658→                el.style.fontFamily = fontFamily;
   659→                if (settings.largeText) {
   660→                  el.style.fontSize = '16px';
   661→                }
   662→              }
   663→            });
   664→
   665→            if (isHighContrast) {
   666→              const rect = document.createElementNS('http://www.w3.org/2000/svg', 'rect');
   667→              rect.setAttribute('width', '100%');
   668→              rect.setAttribute('height', '100%');
   669→              rect.setAttribute('fill', '#000000');
   670→              svgRef.current.insertBefore(rect, svgRef.current.firstChild);
   671→            }
   672→          }
   673→        }, 100);
   674→
   675→        svgRef.current.setAttribute('role', 'img');
   676→        svgRef.current.setAttribute('aria-label', `Mappa mentale: ${title}`);
   677→
   678→        setRendered(true);
   679→      } catch (err) {
   680→        const errorMsg = err instanceof Error ? err.message : String(err);
   681→        setError(errorMsg);
   682→        logger.error('InteractiveMarkMap render error', { error: String(err) });
   683→      }
   684→    };
   685→
   686→    renderMindmap();
   687→  }, [
   688→    nodes,
   689→    title,
   690→    settings.dyslexiaFont,
   691→    settings.highContrast,
   692→    settings.largeText,
   693→    accessibilityMode,
   694→  ]);
   695→
   696→  // Listen for fullscreen changes
   697→  useEffect(() => {
   698→    const handleFullscreenChange = () => {
   699→      setIsFullscreen(!!document.fullscreenElement);
   700→      if (markmapRef.current) {
   701→        setTimeout(() => markmapRef.current?.fit(), 100);
   702→      }
   703→    };
   704→
   705→    document.addEventListener('fullscreenchange', handleFullscreenChange);
   706→    return () => document.removeEventListener('fullscreenchange', handleFullscreenChange);
   707→  }, []);
   708→
   709→  // ============================================================================
   710→  // RENDER
   711→  // ============================================================================
   712→
   713→  return (
   714→    <motion.div
   715→      ref={containerRef}
   716→      initial={{ opacity: 0, scale: 0.95 }}
   717→      animate={{ opacity: 1, scale: 1 }}
   718→      className={cn(
   719→        'rounded-xl border overflow-hidden',
   720→        settings.highContrast
   721→          ? 'border-white bg-black'
   722→          : 'border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800',
   723→        isFullscreen && 'fixed inset-0 z-50 rounded-none',
   724→        className
   725→      )}
   726→      role="region"
   727→      aria-label={`Mappa mentale interattiva: ${title}`}
   728→    >
   729→      {/* Toolbar */}
   730→      <div
   731→        className={cn(
   732→          'flex items-center justify-between px-4 py-2 border-b',
   733→          settings.highContrast
   734→            ? 'border-white bg-black'
   735→            : 'border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-slate-800/50'
   736→        )}
   737→      >
   738→        <div className="flex items-center gap-2">
   739→          <h3
   740→            className={cn(
   741→              'font-semibold',
   742→              settings.dyslexiaFont && 'tracking-wide',
   743→              settings.highContrast ? 'text-yellow-400' : 'text-slate-700 dark:text-slate-200'
   744→            )}
