   898→            <Printer className="w-4 h-4" />
   899→          </button>
   900→        </div>
   901→      </div>
   902→
   903→      {/* Mindmap container - centered with pan/zoom support */}
   904→      <div
   905→        className={cn(
   906→          'flex items-center justify-center overflow-hidden relative',
   907→          settings.highContrast ? 'bg-black' : 'bg-white dark:bg-slate-900',
   908→          isFullscreen && 'flex-1'
   909→        )}
   910→        style={{
   911→          height: isFullscreen ? 'calc(100vh - 60px)' : '500px',
   912→          minHeight: isFullscreen ? 'calc(100vh - 60px)' : '400px',
   913→        }}
   914→      >
