   921→                : 'bg-red-50 dark:bg-red-900/20 border border-red-200 dark:border-red-800 text-red-600 dark:text-red-400'
   922→            )}
   923→            role="alert"
   924→          >
   925→            <strong>Errore:</strong> {error}
   926→          </div>
   927→        ) : (
   928→          <>
   929→            <svg
   930→              ref={svgRef}
   931→              className={cn(
   932→                'absolute inset-0 w-full h-full cursor-grab active:cursor-grabbing',
   933→                !rendered && 'animate-pulse rounded-lg',
   934→                !rendered &&
   935→                  (settings.highContrast ? 'bg-gray-800' : 'bg-slate-100 dark:bg-slate-700/50')
